            long long g = __gcd(dx, dy);
            if (g != 0) {
                dx /= g;
                dy /= g;
            }
            if (dx < 0 || (dx == 0 && dy < 0)) {
                dx = -dx;
                dy = -dy;
            }

            slopeMap[{dx, dy}].emplace_back(points[j][0], points[j][1]);
