                    vector<pair<long long, long long>> quad = {
                        {points[i][0], points[i][1]},
                        {points[j][0], points[j][1]},
                        {points[k][0], points[k][1]},
                        {points[l][0], points[l][1]}
                    };

                    vector<pair<long long, long long>> slopes;
                    for (int a = 0; a < 4; ++a) {
                        for (int b = a + 1; b < 4; ++b) {
                            long long dx = quad[b].first - quad[a].first;
                            long long dy = quad[b].second - quad[a].second;

                            if (dx == 0 && dy == 0) continue;

                            long long g = __gcd(dx, dy);
                            if (g != 0) {
                                dx /= g;
                                dy /= g;
                            }
                            if (dx < 0 || (dx == 0 && dy < 0)) {
                                dx = -dx;
                                dy = -dy;
                            }

                            slopes.emplace_back(dx, dy);
                        }
                    }

                    map<pair<long long, long long>, int> slopeCount;
                    for (auto& s : slopes) {
                        slopeCount[s]++;
                    }

                    bool isTrapezoid = false;
                    for (auto& [s, cnt] : slopeCount) {
                        if (cnt >= 2) {
                            isTrapezoid = true;
                            break;
                        }
                    }

                    if (isTrapezoid) {
                        set<pair<long long, long long>> quadSet(quad.begin(), quad.end());
                        trapezoidMap[quadSet]++;
                    }
                }
            }
        }
    }

