import math
from collections import defaultdict

def solve(points: list[list[int]]) -> int:
    n = len(points)
    if n < 4:
        return 0

    trapezoids = set()

    for i in range(n):
        for j in range(i + 1, n):
            for k in range(j + 1, n):
                for l in range(k + 1, n):
                    # Get the four points
                    p1, p2, p3, p4 = points[i], points[j], points[k], points[l]
                    points_quad = [p1, p2, p3, p4]

                    # Calculate all possible slopes between any two points
                    slopes = []
                    for a in range(4):
                        for b in range(a + 1, 4):
                            x1, y1 = points_quad[a]
                            x2, y2 = points_quad[b]
                            dx = x2 - x1
                            dy = y2 - y1

                            if dx == 0 and dy == 0:
                                continue  # same point, skip

                            # Simplify the slope to avoid floating points
                            gcd_val = math.gcd(dx, dy)
                            if gcd_val != 0:
                                dx //= gcd_val
                                dy //= gcd_val

                            # Ensure consistent representation
                            if dx < 0 or (dx == 0 and dy < 0):
                                dx = -dx
                                dy = -dy

                            slopes.append((dx, dy))

                    # Check if there are at least two pairs of parallel sides
                    slope_counts = defaultdict(int)
                    has_parallel = False
                    for slope in slopes:
                        slope_counts[slope] += 1
                        if slope_counts[slope] >= 2:
                            has_parallel = True
                            break

                    if has_parallel:
                        # Add the sorted tuple of points to the set to avoid duplicates
                        quad_tuple = tuple(sorted((tuple(p1), tuple(p2), tuple(p3), tuple(p4))))
                        trapezoids.add(quad_tuple)

    return len(trapezoids)
