import math
from collections import defaultdict

def solve(points: list[list[int]]) -> int:
    n = len(points)
    trapezoids = set()

    for i in range(n):
        for j in range(i + 1, n):
            for k in range(j + 1, n):
                for l in range(k + 1, n):
                    # Get the four points
                    p1, p2, p3, p4 = points[i], points[j], points[k], points[l]
                    quad = [p1, p2, p3, p4]

                    # Calculate all possible slopes between any two points
                    slopes = []
                    for a in range(4):
                        for b in range(a + 1, 4):
                            dx = quad[b][0] - quad[a][0]
                            dy = quad[b][1] - quad[a][1]

                            if dx == 0 and dy == 0:
                                continue  # same point, skip

                            # Simplify the slope (dx, dy) to its simplest form
                            g = math.gcd(dx, dy)
                            if g != 0:
                                dx //= g
                                dy //= g
                            # Ensure consistent representation
                            if dx < 0 or (dx == 0 and dy < 0):
                                dx = -dx
                                dy = -dy

                            slopes.append((dx, dy))

                    # Check if there are at least two pairs of parallel sides
                    slope_count = defaultdict(int)
                    for slope in slopes:
                        slope_count[slope] += 1

                    is_trapezoid = any(count >= 2 for count in slope_count.values())

                    if is_trapezoid:
                        # Use a frozenset to represent the quadrilateral to avoid duplicates
                        quad_tuple = tuple(tuple(sorted(quad)))
                        trapezoids.add(quad_tuple)

    return len(trapezoids)
